// ── Filter helpers used by ErrorTagModal ────────────────────────────────────

// Step 2 — Which error types are valid for this event?
// Preserves the order in which they first appear in the sheet.
export function getErrorTypesForEvent(eventName) {
  if (!eventName) return []
  const seen = new Set()
  const out = []
  for (const s of TAGGING_SCENARIOS) {
    if (s.event !== eventName) continue
    if (seen.has(s.errorType)) continue
    seen.add(s.errorType)
    out.push(s.errorType)
  }
  return out
}

// Step 3 — For (event + error type), which corrections are valid?
// Returns [{ correction, shortcut, tagged }] in source order.
export function getCorrectionsForScenario(eventName, errorType) {
  if (!eventName || !errorType) return []
  const seen = new Set()
  const out = []
  for (const s of TAGGING_SCENARIOS) {
    if (s.event !== eventName) continue
    if (s.errorType !== errorType) continue
    const key = (s.correction || '') + '|' + (s.correctionSC || '')
    if (seen.has(key)) continue
    seen.add(key)
    out.push({ correction: s.correction, shortcut: s.correctionSC, tagged: s.tagged })
  }
  return out
}

// Step 4 — Some corrections require an additional qualifier (Type column).
// Only returns qualifiers if at least one row in the matching scenarios has one.
// Returns [{ qualifier, shortcut }] or [] if none.
export function getTypeQualifiersForCorrection(eventName, errorType, correction) {
  if (!eventName || !errorType || !correction) return []
  const seen = new Set()
  const out = []
  for (const s of TAGGING_SCENARIOS) {
    if (s.event !== eventName) continue
    if (s.errorType !== errorType) continue
    if (s.correction !== correction) continue
    if (!s.typeQualifier) continue
    const key = s.typeQualifier + '|' + (s.typeSC || '')
    if (seen.has(key)) continue
    seen.add(key)
    out.push({ qualifier: s.typeQualifier, shortcut: s.typeSC })
  }
  return out
}

// Convenience — list of all error types in the canonical order from the sheet
export const ALL_ERROR_TYPES = (() => {
  const seen = new Set()
  const out = []
  for (const s of TAGGING_SCENARIOS) {
    if (seen.has(s.errorType)) continue
    seen.add(s.errorType)
    out.push(s.errorType)
  }
  return out
})()
